import React, { Fragment, useState, useEffect, useRef } from 'react';
import { Card, CardHeader, CardBody, Dropdown, DropdownToggle, DropdownMenu, DropdownItem, Form, Row, Col } from 'reactstrap';
import DataTable from 'react-data-table-component';
import { H3, Btn, Breadcrumbs } from '../../../AbstractElements';
import { Link, useNavigate } from 'react-router-dom';
import { getClientUrlDataToken, postClientUrlWithToken } from '../../../Utils/restUtils';
import { Search, Filter, Status, Export, Import, importFile, Enquiry, EnquiryList, newEnquiry } from '../../../Constant';
import { viewCustomer, viewCustomerRole, getArea, getAreaRole, showEnquiry, showEnquiryRole, enquirystatusCount, enquirystatusCountRole, enquiryChangeStatus, enquiryChangeStatusRole, getUsers, getUsersRole, getitemSelect, getitemSelectRole } from '../../../CommonUrl';
import { useSelector } from 'react-redux';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import 'jspdf-autotable';
import { toast } from 'react-toastify';
import { conditionalRow } from '../../Common/Rowstyle/Rowstyle';
import Widgets from '../../Common/Progress/Widgets';
import moment from 'moment';
import Transparentspinner from '../../Common/Loader/Transparentspinner';
import { CustomerColumns } from '../ColumnHeader/Header';
import OverDues from './OverDues';
import DatePicker from 'react-datepicker';
import Popup from '../../Common/Popup/popup';
import EnquiryImportModal from './EnquiryImportModal';


const EnquiriesList = () => {
  const [spinnerTrans, setspinnerTrans] = useState(false);

  const navigate = useNavigate();
  const authState = useSelector((state) => state.auth);
  const [customerLists, setCustomerList] = useState([]);
  const [resetPaginationToggle, setResetPaginationToggle] = useState(false);
  const [totalRows, setTotalRows] = useState(0);
  const [perPage, setPerPage] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);
  const [users, setUsers] = useState([]);
  const [staticwidgets, setstaticwidgets] = useState([])
  const [itemOption, setitemsoptions] = useState([])
  const [importDrpodown, setimportDrpodown] = useState(false);
  const [modalImport, setModalImport] = useState(false);
  const [dropdownOpen, setDropdownOpen] = useState(false);


  const toggleStyle = { padding: '10px 20px', opacity: '0.8', fontSize: '14px' }

  const isSearched = useRef(null);
  const isArea = useRef(null);
  const searchParams = location.search;
  const params = new URLSearchParams(searchParams);

  const [filters, setFilters] = useState({
    search: params.get('search') || '',
    start_date: params.get('start_date') ? moment(params.get('start_date'), "DD-MM-YYYY").toDate() : '',
    end_date: params.get('end_date') ? moment(params.get('end_date'), "DD-MM-YYYY").toDate() : '',
    userId: params.get("user") || '',
    status: params.get("status") || '',
    product: params?.get('product') || ''
  });
  const [dateRange, setDateRange] = useState([filters.start_date, filters.end_date]);
  const [startDate, endDate] = dateRange
  const [sortConfig, setSortConfig] = useState({ column: '', order: '' });
  const formatStartDate = filters.start_date ? moment(filters.start_date).format("DD-MM-YYYY") : '';
  const formatEndDate = filters.end_date ? moment(filters.end_date).format("DD-MM-YYYY") : '';

  const enquiryStatusOptions =
    [
      { label: 'New', value: 'new' },
      { label: 'Contacted', value: 'contacted' },
      { label: 'Qualified', value: 'qualified' },
      { label: 'Lost', value: 'lost' },
      { label: 'Converted', value: 'converted' },
    ];

  useEffect(() => {
    fetchEnquiry(1);
    getProducts()
    getwidgetsdata();
    userData()
  }, []);




  const handleApiError = (status) => {
    if (status >= 400 && status <= 405) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
    } else if (status >= 500 && status <= 505) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
    } else {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
    }
  };

  const handleSort = (column) => {
    let newOrder = 'asc';
    if (sortConfig.column === column.id) {
      newOrder = sortConfig.order === 'asc' ? 'desc' : 'asc';
    }
    setSortConfig({ column: column.id, order: newOrder });
    fetchEnquiry(currentPage, perPage, filters.search, filters.start_date, filters.end_date, filters.areaFilter, filters.cust_status_Filter, column.id, newOrder);
  };


  const toggleImport = () => setimportDrpodown(!importDrpodown);
  const toggleDropdown = () => setDropdownOpen(!dropdownOpen);


  const handleOpenImport = () => {
    setModalImport(!modalImport)
  }
  const handleNavigateLog = () => {
    navigate('/lead-manage/enquiry/imported-log-list')
  }





  const getwidgetsdata = async () => {
    const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? enquirystatusCount : enquirystatusCountRole);
    if (data.status === true) {
      setstaticwidgets(data.data);
    } else {
      handleApiError(data.status);
    }
  }


  const fetchEnquiry = async (page, size = perPage, searchKey = '', start_date = '', end_date = '', areaFilter = '', cust_status_Filter = '', sortBy = '', sortOrder = '') => {
    setspinnerTrans(true)
    const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? showEnquiry +
      `?page=${page}&page_length=${size}&status=${filters?.status}&search=${filters?.search}&user_id=${filters?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sort_by=${sortBy}&sort_order=${sortOrder}&product_id=${filters?.product}` :
      showEnquiryRole + `?page=${page}&page_length=${size}&status=${filters?.status}&search=${filters?.search}&user_id=${filters?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sort_by=${sortBy}&sort_order=${sortOrder}&product_id=${filters?.product}`);
    if (response.status === true) {
      setResetPaginationToggle(!resetPaginationToggle);
      const SerialNo = (page - 1) * size + 1;
      setCustomerList(response.data.data.map((e, index) => {
        return {
          Si: SerialNo + index,
          name: e.name || 'N/A',
          Mobile: e?.country_code ? "+" + e?.country_code + " " + e?.phone : e?.phone,
          product: e?.product_name || 'N/A',
          Status: e.status || 'N/A',
          created: e?.created_at || 'N/A',
          assigned: e?.assigned_user_name || 'N/A',
          enquiryId: e?.enquiry_id || 'N/A',
          id: e?.id

        }
      }))
      setTotalRows(response.data.total);
    } else {
      handleApiError(response.status);
    }
    setspinnerTrans(false)
  };

  const exportCustomerExcel = async () => {
    setspinnerTrans(true)
    const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ?
      showEnquiry + `?export=customer_data&status=${filters?.status}&search=${filters?.search}&user_id=${filters?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&product_id=${filters?.product}`
      : showEnquiryRole + `?export=customer_data&status=${filters?.status}&search=${filters?.search}&user_id=${filters?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&product_id=${filters?.product}`);
    const dataToExport = response.data.map(({ enquiry_id, name, phone, product_name, status, assigned_user_name, created_at }) => ({ Enquiry_Id: enquiry_id, Name: name, Mobile: phone, Status: status, Product_Name: product_name, Assin_User: assigned_user_name, Create: created_at }));
    if (response.status === true) {
      const ws = XLSX.utils.json_to_sheet(dataToExport);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, 'Customer Data');
      XLSX.writeFile(wb, 'enquiry_report.xlsx');
    } else {
      handleApiError(response.status);
    }
    setspinnerTrans(false)
  };

  const exportCustomerPdf = async () => {
    setspinnerTrans(true)
    const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ?
      showEnquiry + `?export=customer_data&status=${filters?.status}&search=${filters?.search}&user_id=${filters?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&product_id=${filters?.product}`
      : showEnquiryRole + `?export=customer_data&status=${filters?.status}&search=${filters?.search}&user_id=${filters?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&product_id=${filters?.product}`);
    const dataToExport = response.data.map(({ enquiry_id, name, phone, product_name, status, assigned_user_name, created_at }, index) => ({ Sl: index + 1, enquiry_id, name, phone, product_name, status, assigned_user_name, created_at }));
    if (response.status === true) {
      const doc = new jsPDF();
      const heading = "Customer's list";
      doc.setFontSize(18);
      doc.setFont("helvetica", "bold");
      doc.text(heading, 14, 22);
      const columns = ["Sl", "Enquiry Id", "Name", "Mobile", "Product Name", "Status", "Assinged To", "Create On",];
      const rows = dataToExport.map(({ enquiry_id, name, phone, product_name, status, assigned_user_name, created_at }, index) => [index + 1, enquiry_id, name, phone, product_name, status, assigned_user_name, created_at]);
      doc.autoTable({
        head: [columns],
        body: rows,
        margin: { top: 6, left: 6, right: 6, bottom: 6 },
        styles: { fontSize: 10 },
        headStyles: { fillColor: [100, 150, 200] },
      });
      doc.save("enquiry_report.pdf");
    } else {
      handleApiError(response.status);
    }
    setspinnerTrans(false)
  };


  const handlePageChange = page => {
    fetchEnquiry(page, perPage, filters.search, filters.start_date, filters.end_date, filters.areaFilter, filters.cust_status_Filter, sortConfig.column, sortConfig.order);
    setCurrentPage(page);
  };

  const handlePerRowsChange = async (newPerPage, page) => {
    fetchEnquiry(page, newPerPage, filters.search, filters.start_date, filters.end_date, filters.areaFilter, filters.cust_status_Filter, sortConfig.column, sortConfig.order);
    setPerPage(newPerPage);
  };

  const handleFilter = async (e) => {
    e.preventDefault();
    const searchKey = filters?.search;
    const status = filters?.status;
    const userId = filters?.userId;
    const product = filters?.product;
    const areaFilter = isArea?.current?.value;
    // const cust_status_Filter = cust_status.current.value;
    const start_date = startDate ? moment(startDate).format("DD-MM-YYYY") : '';
    const end_date = endDate ? moment(endDate).format("DD-MM-YYYY") : '';
    setFilters({
      searchKey,
      areaFilter,
      start_date,
      end_date,
      status,
      userId,
      product
    });


    const queryParams = new URLSearchParams({
      search: searchKey,
      start_date,
      end_date,
      user: filters?.userId,
      status: filters?.status,
      sortBy: sortConfig.column || '',
      sortOrder: sortConfig.order || '',
      product: filters?.product || '',
    }).toString();

    navigate(`/lead-manage/enquiry?${queryParams}`);
    fetchEnquiry(currentPage, perPage, searchKey, start_date, end_date, areaFilter, sortConfig.column, sortConfig.order);
  };


  //product option
  const getProducts = async () => {
    const item_api = await getClientUrlDataToken(
      authState.apiUrl,
      authState.userRole === 1 ? getitemSelect : getitemSelectRole
    );
    if (item_api.status === true) {
      const data = item_api.data;
      const itemslist = data.map((items) => ({
        value: items.id,
        label: items.name,
      }));
      setitemsoptions(itemslist);
    } else {
      handleApiError(item_api.status);
    }
  };
  const Action = ({ row }) => {
    const navigate = useNavigate();
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const toggleDropdown = () => setDropdownOpen(!dropdownOpen);

    const handleEditClick = () => {
      const editFormURL = `${process.env.PUBLIC_URL}${process.env.PUBLIC_URL}/lead-manage/edit-enquiry?id=${row.id}`;
      navigate(editFormURL);
    };
    const handleView = () => {
      const editFormURL = `${process.env.PUBLIC_URL}${process.env.PUBLIC_URL}/lead-manage/enquiry-details?id=${row.id}`;
      navigate(editFormURL);
    };
    const handleStatusUpdate = async (status) => {
      setspinnerTrans(true);
      const postRequest = {
        status: status,
        enquiry_id: row.id,
      };
      const response = await postClientUrlWithToken(
        authState.apiUrl,
        authState.userRole === 1 ? enquiryChangeStatus : enquiryChangeStatusRole,
        postRequest
      );

      if (response.status === 200) {
        toast.success(response.data.message)
        fetchEnquiry(1)

      } else if (
        response.status >= 400 &&
        response.status <= 405
      ) {
        navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
      } else if (
        response.status >= 500 &&
        response.status <= 505
      ) {
        navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
      } else {
        navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
      }

      setspinnerTrans(false);
    };

    return (
      <Dropdown isOpen={dropdownOpen} toggle={toggleDropdown}>
        <DropdownToggle color="#00000" style={{ fontSize: '14px', zIndex: 1000 }}>
          <i className="fa fa-ellipsis-v"></i>
        </DropdownToggle>
        <DropdownMenu container="body">

          <DropdownItem style={toggleStyle} onClick={() => handleView()}>View</DropdownItem>
          {
            row?.Status !== 'converted' &&
            <>
              <DropdownItem style={toggleStyle} onClick={() => handleEditClick()}>Edit</DropdownItem>
              <DropdownItem style={toggleStyle} onClick={() => handleStatusUpdate('contacted')}>Contacted</DropdownItem>
              <DropdownItem style={toggleStyle} onClick={() => handleStatusUpdate('qualified')}>Qualified</DropdownItem>
              <DropdownItem style={toggleStyle} onClick={() => handleStatusUpdate('lost')}>Lost</DropdownItem>
            </>
          }


          {/* }  */}
        </DropdownMenu>
      </Dropdown>
    );
  };

  const userData = async () => {
    const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getUsers : getUsersRole);
    if (data.status === true) {
      setUsers(data.data);
    } else {
      handleApiError(data.status);
    }
  };
  return (
    <>
      {spinnerTrans && <Transparentspinner />}
      <Breadcrumbs mainTitle={Enquiry} parent="Lead Manger" title={EnquiryList} />
      <Widgets details={staticwidgets} />
      <OverDues authState={authState} />



      <Card className='cardWidth mt-4'>
        <CardHeader style={{ margin: '-25px 0 -40px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <H3>{EnquiryList}</H3>

          <div style={{ display: 'flex' }} >
            <CardBody className="dropdown-basic d-flex flex-wrap gap-2 justify-content-end" style={{ borderRadius: '5px' }}>
              {(authState.userRole === 1 || authState.permissions.includes('store-customer')) &&
                <Link to={`${process.env.PUBLIC_URL}/lead-manage/add-enquiry`} className="btn btn-primary mr-4" style={{ marginLeft: '10px' }}>{newEnquiry}</Link>
              }

              <Dropdown className='m-0 ' isOpen={importDrpodown} toggle={toggleImport}>
                <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4">
                  {Import} <i className="icofont icofont-arrow-down"></i>
                </DropdownToggle>
                <DropdownMenu container="body">
                  <DropdownItem style={toggleStyle} onClick={() => handleOpenImport()} ><i className="fa fa-file-text-o me-2"></i> Import Enquiry</DropdownItem>
                  <DropdownItem style={toggleStyle} onClick={() => handleNavigateLog()}><i className="fa fa-list-alt me-2"></i> Imported Enquiry Logs</DropdownItem>
                  {/* <DropdownItem style={toggleStyle} onClick={() => handleModalImportDue()}><i className="fa fa-file-text-o me-2"></i> Import Customer Dues</DropdownItem>
                                    <DropdownItem style={toggleStyle} onClick={() => handleImportCustomerDueLog()}><i className="fa fa-list-alt me-2"></i> Imported Customer Due Logs</DropdownItem> */}
                </DropdownMenu>
              </Dropdown>
              <Dropdown className='m-0' isOpen={dropdownOpen} toggle={toggleDropdown}>
                <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4">
                  {Export} <i className="icofont icofont-arrow-up"></i>
                </DropdownToggle>
                <DropdownMenu container="body">
                  <DropdownItem style={toggleStyle} onClick={() => exportCustomerExcel()}><i className="fa fa-file-excel-o me-2"></i> Excel</DropdownItem>
                  <DropdownItem style={toggleStyle} onClick={() => exportCustomerPdf()}><i className="fa fa-file-pdf-o me-2"></i> Pdf</DropdownItem>
                </DropdownMenu>
              </Dropdown>
            </CardBody>
          </div>


        </CardHeader>
        <CardBody>
          <span className=''>
            <Form className="needs-validation" noValidate onSubmit={handleFilter}>
              <Row className="ps-3 gap-sm-3 gap-md-2 mb-4 filterGap">
                <Col sm="12" md='5' lg='2'>
                  <input className="form-control" value={filters?.search} onChange={(e) => setFilters({ ...filters, search: e.target.value })} placeholder={Search} type="text"
                  />
                </Col>


                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <DatePicker
                      className="form-control digits w-100"
                      selectsRange
                      startDate={startDate}
                      endDate={endDate}
                      onChange={(update) => {
                        setDateRange(update);
                      }}
                      isClearable={startDate ? true : false}
                      monthsShown={2}
                      popperPlacement="bottom"
                      calendarClassName='parallel-calendar'
                      dateFormat="dd/MM/yyyy"
                      placeholderText='Select Date Range'
                    />
                  </div>
                </Col>
                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <select value={filters?.product} onChange={(e) => { setFilters({ ...filters, product: e.target.value }) }} className='form-control ' name="" id="">
                      <option value=''>Product</option>
                      {
                        itemOption?.map((item) => (
                          <option key={item?.value} value={item?.value}>{item?.label}</option>
                        ))
                      }
                    </select>

                  </div>
                </Col>
                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <select value={filters.userId || ''} onChange={(e) => { setFilters({ ...filters, userId: e.target.value }) }} className='form-control ' name="" id="">
                      <option value=''>Assigned User</option>
                      {
                        users?.map((item) => (
                          <option key={item?.user_id} value={item?.user_id}>{item?.user_name}</option>
                        ))
                      }
                    </select>

                  </div>
                </Col>
                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <select value={filters.status} onChange={(e) => { setFilters({ ...filters, status: e.target.value }) }} className='form-control ' name="" id="">
                      <option value={''}> Status</option>
                      {
                        enquiryStatusOptions?.map((item) => (
                          <option key={item?.value} value={item?.value}>{item?.label}</option>
                        ))
                      }
                    </select>

                  </div>
                </Col>
                <Col sm="12" md="5" lg='1' className="custom-filtrs">
                  <Btn attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                </Col>
              </Row>
            </Form>
          </span>

          <div className="order-history table-responsive">
            <DataTable
              columns={CustomerColumns(authState, Action)}
              data={customerLists}
              // progressPending={loading}
              pagination
              paginationServer
              defaultSortAsc
              onSort={handleSort}
              sortServer
              paginationRowsPerPageOptions={[10, 25, 50, 100]}
              paginationTotalRows={totalRows}
              paginationDefaultPage={currentPage}
              onChangeRowsPerPage={handlePerRowsChange}
              conditionalRowStyles={conditionalRow}
              onChangePage={handlePageChange}
              fixedHeader
            />
          </div>
        </CardBody>
        <Popup isOpen={modalImport} title={'Import Enquiry'} toggler={handleOpenImport} >
          <EnquiryImportModal currentPage={currentPage}
            tablerenderFunc={fetchEnquiry}
            setModal={setModalImport} />
        </Popup>
      </Card>


    </>
  )
}

export default EnquiriesList