import { Link } from "react-router-dom";
import { H4 } from "../../../AbstractElements";
// import CustomerAction from "../ActionCell/CustomerAction";

export const CustomerColumns = (authState, Action) => [
    {
        name: <H4>Sl.No</H4>,
        selector: row => row.Si,
        width: '70px',
        center: true

    },
    {
        name: <i className="fa fa-gears" style={{ fontSize: '15px' }}></i>,
        selector: row => row.action,
        cell: row => <Action row={row} />,
        center: true,
        width: '55px',
    },

    {
        name: <H4>Enquiry ID</H4>,
        id: 'enquiryID',
        selector: row =>
            (authState.userRole === 1 || authState.permissions.includes("show-customer-profile")) ?
                <Link style={{ textDecoration: 'underline' }} to={`${process.env.PUBLIC_URL}/lead-manage/enquiry-details?id=${row.id}`}>
                    {row.enquiryId}
                </Link> : row.enquiryId,
        sortable: true,
        minWidth: '150px',
        wrap: true
    },
    {
        name: <H4>Name</H4>,
        id: 'name',
        selector: row => row.name,
        sortable: true,
        minWidth: '150px',
        wrap: true
    },

    {
        name: <H4>Mobile No</H4>,
        selector: row => row.Mobile,
        id: 'mobile',
        sortable: true,
        minWidth: '160px',
    },
    {
        name: <H4>Product name</H4>,
        selector: row => row.product,
        id: 'product',
        sortable: true,
        minWidth: '160px',
    },


    {
        name: <H4>Status</H4>,
        selector: row => row.Date,
        minWidth: '120px',
        cell: row => (
            <span
                className={` badge-${row.Status}`}
            >
                {row.Status}
            </span>
        ),
    },
    {
        name: <H4>Assigned To</H4>,
        selector: row => row.assigned,
        id: 'assigned',
        sortable: true,
        wrap: true,
        minWidth: '160px'
    },
    {
        name: <H4>Create On</H4>,
        selector: row => row.created,
        id: 'Create',
        minWidth: '160px',

        sortable: true,
        wrap: true,
    },


];
